1	/* parser.h -- PL/SW parser */
2	/* Parses DCL statements and expressions into AST nodes */
3	
4	#ifndef PARSER_H
5	#define PARSER_H
6	
7	#include "lexer.h"
8	#include "ast.h"
9	
10	/* Parser error state */
11	int parse_err;          /* 0 = ok, 1 = error */
12	char parse_errmsg[64];  /* error description */
13	
14	void parse_init(char *src) {
15	    parse_err = 0;
16	    parse_errmsg[0] = 0;
17	    lex_init(src, str_len(src));
18	    lex_scan();  /* prime the first token */
19	}
20	
21	/* Report a parse error */
22	void parse_error(char *msg) {
23	    parse_err = 1;
24	    str_copy(parse_errmsg, msg);
25	    uart_putstr("ERROR: ");
26	    uart_puts(msg);
27	}
28	
29	/* Check if current token matches type */
30	int parse_check(int type) {
31	    return cur_type == type;
32	}
33	
34	/* Consume current token and advance */
35	void parse_advance(void) {
36	    lex_scan();
37	}
38	
39	/* Expect a specific token; consume and advance. Error if wrong. */
40	int parse_expect(int type) {
41	    if (cur_type != type) {
42	        uart_putstr("expected ");
43	        uart_putstr(tok_name(type));
44	        uart_putstr(" got ");
45	        uart_putstr(tok_name(cur_type));
46	        uart_putchar(10);
47	        parse_error("unexpected token");
48	        return 0;
49	    }
50	    parse_advance();
51	    return 1;
52	}
53	
54	/* Try to match a token; consume if matched, return 1. Else return 0. */
55	int parse_match(int type) {
56	    if (cur_type == type) {
57	        parse_advance();
58	        return 1;
59	    }
60	    return 0;
61	}
62	
63	/* --- Type parsing --- */
64	
65	/* Parse a type keyword and return the TYPE_ constant.
66	   Handles INT(n) where n determines INT8/INT16/INT24.
67	   Returns TYPE_NONE if no type keyword found. */
68	int parse_type(void) {
69	    if (cur_type == TOK_INT) {
70	        parse_advance();
71	        /* optional width: INT(8), INT(16), INT(24) */
72	        if (parse_check(TOK_LPAREN)) {
73	            parse_advance();
74	            int width = cur_ival;
75	            parse_expect(TOK_NUM);
76	            parse_expect(TOK_RPAREN);
77	            if (width <= 8) return TYPE_INT8;
78	            if (width <= 16) return TYPE_INT16;
79	            return TYPE_INT24;
80	        }
81	        return TYPE_INT24;  /* default INT = INT(24) */
82	    }
83	    if (cur_type == TOK_BYTE) { parse_advance(); return TYPE_BYTE; }
84	    if (cur_type == TOK_CHAR) { parse_advance(); return TYPE_CHAR; }
85	    if (cur_type == TOK_PTR)  { parse_advance(); return TYPE_PTR; }
86	    if (cur_type == TOK_WORD) { parse_advance(); return TYPE_WORD; }
87	    if (cur_type == TOK_BIT)  { parse_advance(); return TYPE_BIT; }
88	    return TYPE_NONE;
89	}
90	
91	/* --- Storage class parsing --- */
92	
93	/* Parse optional storage class. Returns STOR_ constant. */
94	int parse_storage(void) {
95	    if (cur_type == TOK_STATIC)   { parse_advance(); return STOR_STATIC; }
96	    if (cur_type == TOK_AUTO)     { parse_advance(); return STOR_AUTO; }
97	    if (cur_type == TOK_EXTERNAL) { parse_advance(); return STOR_EXTERNAL; }
98	    if (cur_type == TOK_BASED)    { parse_advance(); return STOR_BASED; }
99	    return STOR_AUTO;
100	}
101	
102	/* --- INIT parsing --- */
103	
104	/* Parse INIT(value) -- returns node index or NODE_NULL */
105	int parse_init_attr(void) {
106	    if (cur_type != TOK_INIT) return NODE_NULL;
107	    parse_advance();  /* consume INIT */
108	    parse_expect(TOK_LPAREN);
109	    int init_node = NODE_NULL;
110	    if (cur_type == TOK_NUM) {
111	        init_node = nd_literal(cur_ival);
112	        parse_advance();
113	    } else if (cur_type == TOK_STRING) {
114	        init_node = nd_alloc(NODE_LITERAL);
115	        if (init_node != NODE_NULL) {
116	            nd_set_name(init_node, cur_text);
117	            nd_type[init_node] = TYPE_CHAR;
118	        }
119	        parse_advance();
120	    } else {
121	        parse_error("expected literal in INIT");
122	        return NODE_NULL;
123	    }
124	    parse_expect(TOK_RPAREN);
125	    return init_node;
126	}
127	
128	/* --- DCL parsing --- */
129	
130	/* Parse a single scalar/array declaration field.
131	   Used for both top-level DCL and level-based fields.
132	   Returns the DCL node index. */
133	int parse_dcl_field(int level) {
134	    if (cur_type != TOK_IDENT) {
135	        parse_error("expected identifier in DCL");
136	        return NODE_NULL;
137	    }
138	
139	    /* Save name in arena (avoids large stack local) */
140	    int nlen = str_len(cur_text);
141	    char *name = arena_alloc(nlen + 1);
142	    if (!name) {
143	        parse_error("arena full");
144	        return NODE_NULL;
145	    }
146	    str_copy(name, cur_text);
147	    parse_advance();
148	
149	    /* Check for array dimension: NAME(dim) */
150	    int dim = 0;
151	    if (parse_check(TOK_LPAREN)) {
152	        parse_advance();
153	        if (cur_type == TOK_NUM) {
154	            dim = cur_ival;
155	            parse_advance();
156	        } else {
157	            parse_error("expected number for array dimension");
158	            return NODE_NULL;
159	        }
160	        parse_expect(TOK_RPAREN);
161	    }
162	
163	    /* Parse type */
164	    int type = parse_type();
165	
166	    /* Parse storage class */
167	    int stor = parse_storage();
168	
169	    /* Parse optional INIT */
170	    int init = parse_init_attr();
171	
172	    /* Build the DCL node */
173	    int n = nd_alloc(NODE_DCL);
174	    if (n == NODE_NULL) {
175	        parse_error("node pool full");
176	        return NODE_NULL;
177	    }
178	    /* name is already in arena, just assign directly */
179	    nd_name[n] = name;
180	    nd_type[n] = type;
181	    nd_stor[n] = stor;
182	    nd_level[n] = level;
183	    nd_ival[n] = dim;
184	    nd_right[n] = init;  /* init expression, or NODE_NULL */
185	
186	    return n;
187	}
188	
189	/* Parse a level-based record declaration.
190	   Called after DCL and the first level number have been consumed.
191	   Syntax: DCL 1 NAME, 3 FIELD TYPE, 3 FIELD TYPE, ...;
192	
193	   Level 1 = record container, 3+ = fields.
194	   Lower level numbers start new groups. */
195	int parse_dcl_record(int first_level) {
196	    /* Parse the record name */
197	    if (cur_type != TOK_IDENT) {
198	        parse_error("expected record name");
199	        return NODE_NULL;
200	    }
201	
202	    /* Create record container node */
203	    int rec = nd_alloc(NODE_DCL);
204	    if (rec == NODE_NULL) {
205	        parse_error("node pool full");
206	        return NODE_NULL;
207	    }
208	    nd_set_name(rec, cur_text);
209	    nd_type[rec] = TYPE_RECORD;
210	    nd_level[rec] = first_level;
211	    parse_advance();
212	
213	    /* Parse optional storage class on record itself */
214	    nd_stor[rec] = parse_storage();
215	
216	    /* Expect comma or semicolon after record name */
217	    if (!parse_match(TOK_COMMA)) {
218	        /* Record with no fields -- just a named type */
219	        parse_expect(TOK_SEMI);
220	        return rec;
221	    }
222	
223	    /* Parse fields: level NAME type, ... ; */
224	    while (!parse_err) {
225	        /* Expect a level number */
226	        if (cur_type != TOK_NUM) {
227	            parse_error("expected level number");
228	            return rec;
229	        }
230	        int field_level = cur_ival;
231	        parse_advance();
232	
233	        /* Parse the field */
234	        int field = parse_dcl_field(field_level);
235	        if (field == NODE_NULL) return rec;
236	
237	        /* Append field as child of record */
238	        nd_append(rec, field);
239	
240	        /* Comma means more fields, semicolon ends */
241	        if (parse_check(TOK_SEMI)) {
242	            parse_advance();
243	            break;
244	        }
245	        if (!parse_match(TOK_COMMA)) {
246	            parse_error("expected , or ; in record DCL");
247	            return rec;
248	        }
249	    }
250	
251	    return rec;
252	}
253	
254	/* Parse a DCL statement. Handles:
255	   - DCL NAME TYPE;
256	   - DCL NAME(dim) TYPE;
257	   - DCL NAME TYPE STATIC;
258	   - DCL NAME TYPE INIT(val);
259	   - DCL 1 NAME, 3 FIELD TYPE, ...;
260	   Returns the root DCL node index. */
261	int parse_dcl(void) {
262	    /* Consume DCL or DECLARE */
263	    if (cur_type != TOK_DCL && cur_type != TOK_DECLARE) {
264	        parse_error("expected DCL");
265	        return NODE_NULL;
266	    }
267	    parse_advance();
268	
269	    /* Check if level-based record: DCL <number> ... */
270	    if (cur_type == TOK_NUM) {
271	        int level = cur_ival;
272	        parse_advance();
273	        return parse_dcl_record(level);
274	    }
275	
276	    /* Simple scalar or array declaration */
277	    int n = parse_dcl_field(0);
278	    if (n == NODE_NULL) return NODE_NULL;
279	
280	    /* Expect semicolon */
281	    parse_expect(TOK_SEMI);
282	
283	    return n;
284	}
285	
286	/* --- Procedure parsing --- */
287	
288	/* Option flag bits for PROC OPTIONS */
289	#define OPT_FREESTANDING 1
290	#define OPT_NAKED        2
291	#define OPT_LEAF         4
292	
293	/* Forward declaration */
294	int parse_proc(void);
295	
296	/* --- Expression parsing --- */
297	
298	/* Operator precedence levels (low to high) */
299	#define PREC_NONE    0
300	#define PREC_OR      1   /* OR (logical) */
301	#define PREC_AND     2   /* AND (logical) */
302	#define PREC_BOR     3   /* | (bitwise OR) */
303	#define PREC_BXOR    4   /* ^ (bitwise XOR) */
304	#define PREC_BAND    5   /* & (bitwise AND) */
305	#define PREC_EQ      6   /* = != */
306	#define PREC_CMP     7   /* < > <= >= */
307	#define PREC_SHIFT   8   /* << >> */
308	#define PREC_ADD     9   /* + - */
309	#define PREC_MUL    10   /* * / */
310	
311	/* Get precedence of a binary operator token */
312	int tok_prec(int type) {
313	    if (type == TOK_OR) return PREC_OR;
314	    if (type == TOK_AND) return PREC_AND;
315	    if (type == TOK_PIPE) return PREC_BOR;
316	    if (type == TOK_CARET) return PREC_BXOR;
317	    if (type == TOK_AMP) return PREC_BAND;
318	    if (type == TOK_EQ) return PREC_EQ;
319	    if (type == TOK_NE) return PREC_EQ;
320	    if (type == TOK_LT) return PREC_CMP;
321	    if (type == TOK_GT) return PREC_CMP;
322	    if (type == TOK_LE) return PREC_CMP;
323	    if (type == TOK_GE) return PREC_CMP;
324	    if (type == TOK_SHL) return PREC_SHIFT;
325	    if (type == TOK_SHR) return PREC_SHIFT;
326	    if (type == TOK_PLUS) return PREC_ADD;
327	    if (type == TOK_MINUS) return PREC_ADD;
328	    if (type == TOK_STAR) return PREC_MUL;
329	    if (type == TOK_SLASH) return PREC_MUL;
330	    return PREC_NONE;
331	}
332	
333	/* Forward declarations */
334	int parse_expr(void);
335	int parse_expr_prec(int min_prec);
336	int parse_stmt(void);
337	
338	/* Parse a primary expression (atom + postfix) */
339	int parse_primary(void) {
340	    /* Unary minus */
341	    if (cur_type == TOK_MINUS) {
342	        parse_advance();
343	        int operand = parse_primary();
344	        return nd_unop(TOK_MINUS, operand);
345	    }
346	    /* Bitwise NOT ~ */
347	    if (cur_type == TOK_TILDE) {
348	        parse_advance();
349	        int operand = parse_primary();
350	        return nd_unop(TOK_TILDE, operand);
351	    }
352	    /* Logical NOT */
353	    if (cur_type == TOK_NOT) {
354	        parse_advance();
355	        int operand = parse_primary();
356	        return nd_unop(TOK_NOT, operand);
357	    }
358	
359	    /* ADDR(expr) -- address-of */
360	    if (cur_type == TOK_ADDR) {
361	        parse_advance();
362	        parse_expect(TOK_LPAREN);
363	        int operand = parse_expr();
364	        parse_expect(TOK_RPAREN);
365	        int n = nd_alloc(NODE_ADDR);
366	        if (n != NODE_NULL) {
367	            nd_left[n] = operand;
368	        }
369	        return n;
370	    }
371	
372	    /* Parenthesized sub-expression */
373	    if (cur_type == TOK_LPAREN) {
374	        parse_advance();
375	        int e = parse_expr();
376	        parse_expect(TOK_RPAREN);
377	        return e;
378	    }
379	
380	    /* Number literal */
381	    if (cur_type == TOK_NUM) {
382	        int n = nd_literal(cur_ival);
383	        parse_advance();
384	        return n;
385	    }
386	
387	    /* String literal */
388	    if (cur_type == TOK_STRING) {
389	        int n = nd_alloc(NODE_LITERAL);
390	        if (n != NODE_NULL) {
391	            nd_set_name(n, cur_text);
392	            nd_type[n] = TYPE_CHAR;
393	        }
394	        parse_advance();
395	        return n;
396	    }
397	
398	    /* Identifier -- may be followed by call(args) */
399	    if (cur_type == TOK_IDENT) {
400	        int nlen = str_len(cur_text);
401	        char *name = arena_alloc(nlen + 1);
402	        if (name) str_copy(name, cur_text);
403	        parse_advance();
404	
405	        /* Function call / array subscript: name(args...) */
406	        if (cur_type == TOK_LPAREN) {
407	            parse_advance();
408	            int args = NODE_NULL;
409	            int tail = NODE_NULL;
410	            if (cur_type != TOK_RPAREN) {
411	                args = parse_expr();
412	                tail = args;
413	                while (cur_type == TOK_COMMA) {
414	                    parse_advance();
415	                    int a = parse_expr();
416	                    if (tail != NODE_NULL) {
417	                        nd_next[tail] = a;
418	                    }
419	                    tail = a;
420	                }
421	            }
422	            parse_expect(TOK_RPAREN);
423	            int n = nd_alloc(NODE_CALL);
424	            if (n != NODE_NULL) {
425	                nd_name[n] = name;
426	                nd_left[n] = args;
427	            }
428	            return n;
429	        }
430	
431	        /* Plain identifier */
432	        int n = nd_alloc(NODE_IDENT);
433	        if (n != NODE_NULL) {
434	            nd_name[n] = name;
435	        }
436	        return n;
437	    }
438	
439	    parse_error("expected expression");
440	    return NODE_NULL;
441	}
442	
443	/* Parse postfix operators: .field and ->field */
444	int parse_postfix(int left) {
445	    while (!parse_err) {
446	        if (cur_type == TOK_DOT) {
447	            parse_advance();
448	            if (cur_type != TOK_IDENT) {
449	                parse_error("expected field name");
450	                return left;
451	            }
452	            int n = nd_alloc(NODE_FIELD_ACCESS);
453	            if (n != NODE_NULL) {
454	                nd_left[n] = left;
455	                nd_set_name(n, cur_text);
456	            }
457	            parse_advance();
458	            left = n;
459	            continue;
460	        }
461	        if (cur_type == TOK_ARROW) {
462	            parse_advance();
463	            if (cur_type != TOK_IDENT) {
464	                parse_error("expected field name after ->");
465	                return left;
466	            }
467	            int n = nd_alloc(NODE_DEREF);
468	            if (n != NODE_NULL) {
469	                nd_left[n] = left;
470	                nd_set_name(n, cur_text);
471	            }
472	            parse_advance();
473	            left = n;
474	            continue;
475	        }
476	        break;
477	    }
478	    return left;
479	}
480	
481	/* Precedence-climbing expression parser */
482	int parse_expr_prec(int min_prec) {
483	    int left = parse_primary();
484	    if (left == NODE_NULL) return NODE_NULL;
485	    left = parse_postfix(left);
486	
487	    while (!parse_err) {
488	        int prec = tok_prec(cur_type);
489	        if (prec == PREC_NONE || prec < min_prec) break;
490	
491	        int op = cur_type;
492	        parse_advance();
493	        int right = parse_expr_prec(prec + 1);
494	        left = nd_binop(op, left, right);
495	        left = parse_postfix(left);
496	    }
497	
498	    return left;
499	}
500	
501	/* Parse a full expression */
502	int parse_expr(void) {
503	    return parse_expr_prec(PREC_OR);
504	}
505	
506	/* --- Statement parsing --- */
507	
508	/* Parse a block of statements (until END or EOF).
509	   Returns a BLOCK node with statements as children. */
510	int parse_block(void) {
511	    int blk = nd_alloc(NODE_BLOCK);
512	    while (!parse_err && cur_type != TOK_END && cur_type != TOK_EOF) {
513	        int s = parse_stmt();
514	        if (s != NODE_NULL) {
515	            nd_append(blk, s);
516	        }
517	    }
518	    return blk;
519	}
520	
521	/* Parse a single statement.
522	   Handles: assignment, IF, DO (WHILE/count/block), CALL,
523	   RETURN, DCL, and expression statements. */
524	int parse_stmt(void) {
525	    int n;
526	    int cond;
527	    int then_body;
528	    int else_body;
529	    int body;
530	    int args;
531	    int tail;
532	    int expr;
533	    int lhs;
534	    int rhs;
535	    int start_expr;
536	    int end_expr;
537	    char *name;
538	    int nlen;
539	
540	    if (parse_err) return NODE_NULL;
541	
542	    /* IF (cond) THEN stmt ELSE stmt */
543	    if (cur_type == TOK_IF) {
544	        parse_advance();
545	        cond = parse_expr();
546	        parse_expect(TOK_THEN);
547	
548	        /* Then branch: DO;...END; block or single statement */
549	        if (cur_type == TOK_DO) {
550	            parse_advance();
551	            parse_expect(TOK_SEMI);
552	            then_body = parse_block();
553	            parse_expect(TOK_END);
554	            parse_expect(TOK_SEMI);
555	        } else {
556	            then_body = parse_stmt();
557	        }
558	
559	        /* Optional ELSE */
560	        else_body = NODE_NULL;
561	        if (cur_type == TOK_ELSE) {
562	            parse_advance();
563	            if (cur_type == TOK_DO) {
564	                parse_advance();
565	                parse_expect(TOK_SEMI);
566	                else_body = parse_block();
567	                parse_expect(TOK_END);
568	                parse_expect(TOK_SEMI);
569	            } else {
570	                else_body = parse_stmt();
571	            }
572	        }
573	
574	        n = nd_alloc(NODE_IF);
575	        if (n != NODE_NULL) {
576	            nd_left[n] = cond;
577	            nd_right[n] = then_body;
578	            nd_ival[n] = else_body;  /* else branch index, or NODE_NULL */
579	        }
580	        return n;
581	    }
582	
583	    /* DO variants */
584	    if (cur_type == TOK_DO) {
585	        parse_advance();
586	
587	        /* DO WHILE (cond); ... END; */
588	        if (cur_type == TOK_WHILE) {
589	            parse_advance();
590	            parse_expect(TOK_LPAREN);
591	            cond = parse_expr();
592	            parse_expect(TOK_RPAREN);
593	            parse_expect(TOK_SEMI);
594	            body = parse_block();
595	            parse_expect(TOK_END);
596	            parse_expect(TOK_SEMI);
597	
598	            n = nd_alloc(NODE_DO_WHILE);
599	            if (n != NODE_NULL) {
600	                nd_left[n] = cond;
601	                nd_right[n] = body;
602	            }
603	            return n;
604	        }
605	
606	        /* DO I = start TO end; ... END; */
607	        if (cur_type == TOK_IDENT) {
608	            nlen = str_len(cur_text);
609	            name = arena_alloc(nlen + 1);
610	            if (name) str_copy(name, cur_text);
611	            parse_advance();
612	
613	            if (cur_type == TOK_EQ) {
614	                parse_advance();
615	                start_expr = parse_expr();
616	                parse_expect(TOK_TO);
617	                end_expr = parse_expr();
618	                parse_expect(TOK_SEMI);
619	                body = parse_block();
620	                parse_expect(TOK_END);
621	                parse_expect(TOK_SEMI);
622	
623	                n = nd_alloc(NODE_DO_COUNT);
624	                if (n != NODE_NULL) {
625	                    nd_name[n] = name;
626	                    nd_left[n] = start_expr;
627	                    nd_ival[n] = end_expr;  /* end expr node index */
628	                    nd_right[n] = body;
629	                }
630	                return n;
631	            }
632	
633	            parse_error("expected = in DO count");
634	            return NODE_NULL;
635	        }
636	
637	        /* DO; ... END; (simple block) */
638	        parse_expect(TOK_SEMI);
639	        body = parse_block();
640	        parse_expect(TOK_END);
641	        parse_expect(TOK_SEMI);
642	        return body;
643	    }
644	
645	    /* CALL proc(args); -- proc name may be a keyword token */
646	    if (cur_type == TOK_CALL) {
647	        parse_advance();
648	        if (!is_alpha(cur_text[0])) {
649	            parse_error("expected proc name after CALL");
650	            return NODE_NULL;
651	        }
652	        nlen = str_len(cur_text);
653	        name = arena_alloc(nlen + 1);
654	        if (name) str_copy(name, cur_text);
655	        parse_advance();
656	
657	        args = NODE_NULL;
658	        if (cur_type == TOK_LPAREN) {
659	            parse_advance();
660	            tail = NODE_NULL;
661	            if (cur_type != TOK_RPAREN) {
662	                args = parse_expr();
663	                tail = args;
664	                while (cur_type == TOK_COMMA) {
665	                    parse_advance();
666	                    expr = parse_expr();
667	                    if (tail != NODE_NULL) nd_next[tail] = expr;
668	                    tail = expr;
669	                }
670	            }
671	            parse_expect(TOK_RPAREN);
672	        }
673	        parse_expect(TOK_SEMI);
674	
675	        n = nd_alloc(NODE_CALL);
676	        if (n != NODE_NULL) {
677	            nd_name[n] = name;
678	            nd_left[n] = args;
679	        }
680	        return n;
681	    }
682	
683	    /* RETURN(expr); or RETURN; */
684	    if (cur_type == TOK_RETURN) {
685	        parse_advance();
686	        expr = NODE_NULL;
687	        if (cur_type == TOK_LPAREN) {
688	            parse_advance();
689	            expr = parse_expr();
690	            parse_expect(TOK_RPAREN);
691	        }
692	        parse_expect(TOK_SEMI);
693	        return nd_return(expr);
694	    }
695	
696	    /* DCL / DECLARE */
697	    if (cur_type == TOK_DCL || cur_type == TOK_DECLARE) {
698	        return parse_dcl();
699	    }
700	
701	    /* Assignment or expression statement.
702	       Parse lvalue (primary + postfix), then check for = */
703	    lhs = parse_primary();
704	    if (lhs == NODE_NULL) return NODE_NULL;
705	    lhs = parse_postfix(lhs);
706	
707	    if (cur_type == TOK_EQ) {
708	        parse_advance();
709	        rhs = parse_expr();
710	        parse_expect(TOK_SEMI);
711	
712	        /* Convert CALL to ARRAY_ACCESS for subscript assignment */
713	        if (nd_kind[lhs] == NODE_CALL) {
714	            nd_kind[lhs] = NODE_ARRAY_ACCESS;
715	        }
716	
717	        return nd_assign(lhs, rhs);
718	    }
719	
720	    /* Expression statement (e.g., bare function call) */
721	    parse_expect(TOK_SEMI);
722	    return lhs;
723	}
724	
725	/* --- Procedure parser --- */
726	
727	/* Parse a parameter: NAME TYPE
728	   Returns a PARAM node with name and type set. */
729	int parse_param(void) {
730	    int n;
731	    int nlen;
732	    char *name;
733	    int type;
734	
735	    if (!is_alpha(cur_text[0])) {
736	        parse_error("expected param name");
737	        return NODE_NULL;
738	    }
739	    nlen = str_len(cur_text);
740	    name = arena_alloc(nlen + 1);
741	    if (name) str_copy(name, cur_text);
742	    parse_advance();
743	
744	    type = parse_type();
745	
746	    n = nd_alloc(NODE_PARAM);
747	    if (n != NODE_NULL) {
748	        nd_name[n] = name;
749	        nd_type[n] = type;
750	    }
751	    return n;
752	}
753	
754	/* Parse PROC name(params) OPTIONS(...) RETURNS(type); body END;
755	   Syntax:
756	     PROC NAME;                           -- no params, no options
757	     PROC NAME(A INT, B PTR);             -- with params
758	     PROC NAME OPTIONS(FREESTANDING);     -- with options
759	     PROC NAME(A INT) RETURNS(INT);       -- with return type
760	     PROC NAME(A INT) OPTIONS(NAKED) RETURNS(BYTE); body END;
761	
762	   PROC node layout:
763	     nd_name  = procedure name
764	     nd_left  = first parameter (PARAM nodes linked via nd_next)
765	     nd_right = body (BLOCK node)
766	     nd_ival  = option flags (OPT_FREESTANDING | OPT_NAKED | OPT_LEAF)
767	     nd_stor  = return type (TYPE_ constant, TYPE_NONE if no RETURNS) */
768	int parse_proc(void) {
769	    int n;
770	    int nlen;
771	    char *name;
772	    int params;
773	    int ptail;
774	    int p;
775	    int opts;
776	    int ret_type;
777	    int body;
778	
779	    if (cur_type != TOK_PROC) {
780	        parse_error("expected PROC");
781	        return NODE_NULL;
782	    }
783	    parse_advance();
784	
785	    /* Procedure name -- may be a keyword token (like INIT) */
786	    if (!is_alpha(cur_text[0])) {
787	        parse_error("expected proc name");
788	        return NODE_NULL;
789	    }
790	    nlen = str_len(cur_text);
791	    name = arena_alloc(nlen + 1);
792	    if (name) str_copy(name, cur_text);
793	    parse_advance();
794	
795	    /* Optional parameter list */
796	    params = NODE_NULL;
797	    ptail = NODE_NULL;
798	    if (cur_type == TOK_LPAREN) {
799	        parse_advance();
800	        if (cur_type != TOK_RPAREN) {
801	            params = parse_param();
802	            ptail = params;
803	            while (cur_type == TOK_COMMA && !parse_err) {
804	                parse_advance();
805	                p = parse_param();
806	                if (ptail != NODE_NULL) nd_next[ptail] = p;
807	                ptail = p;
808	            }
809	        }
810	        parse_expect(TOK_RPAREN);
811	    }
812	
813	    /* Optional OPTIONS(keyword, ...) */
814	    opts = 0;
815	    if (cur_type == TOK_OPTIONS) {
816	        parse_advance();
817	        parse_expect(TOK_LPAREN);
818	        while (cur_type != TOK_RPAREN && !parse_err) {
819	            if (cur_type == TOK_FREESTANDING) {
820	                opts = opts | OPT_FREESTANDING;
821	                parse_advance();
822	            } else if (cur_type == TOK_NAKED) {
823	                opts = opts | OPT_NAKED;
824	                parse_advance();
825	            } else if (cur_type == TOK_LEAF) {
826	                opts = opts | OPT_LEAF;
827	                parse_advance();
828	            } else {
829	                parse_error("unknown OPTION");
830	                return NODE_NULL;
831	            }
832	            if (cur_type == TOK_COMMA) parse_advance();
833	        }
834	        parse_expect(TOK_RPAREN);
835	    }
836	
837	    /* Optional RETURNS(type) */
838	    ret_type = TYPE_NONE;
839	    if (cur_type == TOK_RETURNS) {
840	        parse_advance();
841	        parse_expect(TOK_LPAREN);
842	        ret_type = parse_type();
843	        if (ret_type == TYPE_NONE) {
844	            parse_error("expected type in RETURNS");
845	            return NODE_NULL;
846	        }
847	        parse_expect(TOK_RPAREN);
848	    }
849	
850	    /* Semicolon after declaration header */
851	    parse_expect(TOK_SEMI);
852	
853	    /* Parse body: statements until END */
854	    body = parse_block();
855	
856	    /* Expect END and optional proc name after END */
857	    parse_expect(TOK_END);
858	    /* Optional name after END (e.g. END foo;) -- skip if identifier */
859	    if (is_alpha(cur_text[0]) && cur_type != TOK_SEMI) {
860	        parse_advance();
861	    }
862	    parse_expect(TOK_SEMI);
863	
864	    /* Build PROC node */
865	    n = nd_alloc(NODE_PROC);
866	    if (n != NODE_NULL) {
867	        nd_name[n] = name;
868	        nd_left[n] = params;
869	        nd_right[n] = body;
870	        nd_ival[n] = opts;
871	        nd_stor[n] = ret_type;
872	    }
873	    return n;
874	}
875	
876	#endif
