229	/* Print a single node for debugging */
230	void nd_print(int n, int depth) {
231	    if (n == NODE_NULL) return;
232	    int d = 0;
233	    while (d < depth) {
234	        uart_putstr("  ");
235	        d = d + 1;
236	    }
237	    uart_putstr(nd_kind_name(nd_kind[n]));
238	    if (nd_name[n]) {
239	        uart_putstr(" name=");
240	        uart_putstr(nd_name[n]);
241	    }
242	    if (nd_kind[n] == NODE_LITERAL) {
243	        uart_putstr(" val=");
244	        print_int(nd_ival[n]);
245	    }
246	    if (nd_kind[n] == NODE_BINOP || nd_kind[n] == NODE_UNOP) {
247	        uart_putstr(" op=");
248	        uart_putstr(tok_name(nd_ival[n]));
249	    }
250	    if (nd_type[n] != TYPE_NONE) {
251	        uart_putstr(" type=");
252	        uart_putstr(nd_type_name(nd_type[n]));
253	    }
254	    if (nd_kind[n] == NODE_DCL) {
255	        if (nd_stor[n] == STOR_STATIC) uart_putstr(" STATIC");
256	        if (nd_stor[n] == STOR_EXTERNAL) uart_putstr(" EXTERNAL");
257	        if (nd_level[n] > 0) {
258	            uart_putstr(" lv=");
259	            print_int(nd_level[n]);
260	        }
261	        if (nd_ival[n] > 0) {
262	            uart_putstr(" dim=");
263	            print_int(nd_ival[n]);
264	        }
265	    }
266	    if (nd_kind[n] == NODE_PROC) {
267	        /* nd_ival stores option flags (bit 0=FREESTANDING, 1=NAKED, 2=LEAF) */
268	        if (nd_ival[n] & 1) uart_putstr(" FREESTANDING");
269	        if (nd_ival[n] & 2) uart_putstr(" NAKED");
270	        if (nd_ival[n] & 4) uart_putstr(" LEAF");
271	        /* nd_stor stores return type */
272	        if (nd_stor[n] != TYPE_NONE) {
273	            uart_putstr(" returns=");
274	            uart_putstr(nd_type_name(nd_stor[n]));
275	        }
276	    }
277	    uart_putchar(10);
278	}
279	
280	/* Recursively dump a tree */
281	void nd_dump(int n, int depth) {
282	    int d;
283	    int p;
284	    if (n == NODE_NULL) return;
285	    nd_print(n, depth);
286	    /* PROC: dump params then body with labels */
287	    if (nd_kind[n] == NODE_PROC) {
288	        /* Dump parameter list */
289	        p = nd_left[n];
290	        if (p != NODE_NULL) {
291	            d = 0;
292	            while (d < depth + 1) { uart_putstr("  "); d = d + 1; }
293	            uart_puts("(PARAMS)");
294	            while (p != NODE_NULL) {
295	                nd_print(p, depth + 2);
296	                p = nd_next[p];
297	            }
298	        }
299	        /* Dump body */
300	        if (nd_right[n] != NODE_NULL) {
301	            d = 0;
302	            while (d < depth + 1) { uart_putstr("  "); d = d + 1; }
303	            uart_puts("(BODY)");
304	            nd_dump(nd_right[n], depth + 2);
305	        }
306	        nd_dump(nd_next[n], depth);
307	        return;
308	    }
309	    nd_dump(nd_left[n], depth + 1);
310	    nd_dump(nd_right[n], depth + 1);
311	    /* IF: dump else branch stored in nd_ival */
312	    if (nd_kind[n] == NODE_IF && nd_ival[n] != NODE_NULL) {
313	        d = 0;
314	        while (d < depth + 1) { uart_putstr("  "); d = d + 1; }
315	        uart_puts("(ELSE)");
316	        nd_dump(nd_ival[n], depth + 1);
317	    }
318	    /* DO_COUNT: dump end expression stored in nd_ival */
319	    if (nd_kind[n] == NODE_DO_COUNT && nd_ival[n] != NODE_NULL) {
320	        d = 0;
321	        while (d < depth + 1) { uart_putstr("  "); d = d + 1; }
322	        uart_puts("(TO)");
323	        nd_dump(nd_ival[n], depth + 1);
324	    }
325	    nd_dump(nd_next[n], depth);
326	}
327	
328	#endif
